const body = $json.body ? $json.body : $json;
const now = new Date();
const hour = (body.hourOverride !== undefined && body.hourOverride !== null) ? body.hourOverride : now.getHours();
return [{
  json: {
    originLat: body.origin && body.origin.lat,
    originLng: body.origin && body.origin.lng,
    destLat: body.destination && body.destination.lat,
    destLng: body.destination && body.destination.lng,
    hour: hour,
    timeOfDayOverride: body.timeOfDayOverride || null,
    routeType: body.routeType || null,
    isTouristCity: Boolean(body.isTouristCity),
    hasDestination: Boolean(body.destination),
    destinationLabel: body.destinationLabel || null,
    originLabel: body.originLabel || null
  }
}];

const prep = $('Prepare').item.json;

let weather = { isRaining: false, description: 'Unknown', tempC: null };
try {
  const w = $('Get Weather').item.json;
  const code = w.current ? w.current.weather_code : null;
  const rainCodes = [51,53,55,56,57,61,63,65,66,67,80,81,82,95,96,99];
  weather = {
    isRaining: rainCodes.indexOf(code) !== -1,
    description: rainCodes.indexOf(code) !== -1 ? 'Rain' : 'Clear',
    tempC: w.current ? w.current.temperature_2m : null
  };
} catch (e) {}

let route = { etaMinutes: null, etaSeconds: null, trafficLevel: 'unknown', source: 'none' };
try {
  const r = $('Get Route').item.json;
  const dur = (r.routes && r.routes[0]) ? r.routes[0].duration : null;
  if (dur) {
    route = {
      etaMinutes: Math.round(dur / 60),
      etaSeconds: Math.round(dur),
      trafficLevel: 'estimated (OSRM has no live traffic feed)',
      source: 'live-osrm'
    };
  }
} catch (e) {}

function timeOfDay(hour, override) {
  if (override) return override;
  if (hour >= 5 && hour < 11) return 'morning';
  if (hour >= 11 && hour < 17) return 'afternoon';
  if (hour >= 17 && hour < 21) return 'evening';
  return 'late_night';
}
const tod = timeOfDay(prep.hour, prep.timeOfDayOverride);

const dest = (prep.destinationLabel || '').toLowerCase();
const origin = (prep.originLabel || '').toLowerCase();
const isGym = /gym|fitness|workout/.test(dest);
const isHome = /home/.test(dest);

let scenario;
if (prep.routeType === 'fitness_outbound' || (isGym && tod !== 'morning')) {
  scenario = { id: 'fitness_to_gym', label: 'Fitness Loop - To Gym', rationale: 'High-BPM push before your workout.', moodTags: ['gym','high-octane','motivational'], bpmRange: [140,170] };
} else if (prep.routeType === 'fitness_return' || (isHome && /gym/.test(origin))) {
  scenario = { id: 'fitness_from_gym', label: 'Fitness Loop - Cool Down', rationale: 'Downtempo accomplishment mix to cool down.', moodTags: ['gym','cool-down','accomplishment'], bpmRange: [80,100] };
} else if (prep.isTouristCity || prep.routeType === 'tourist') {
  scenario = { id: 'tourist_mode', label: 'Tourist Mode', rationale: 'Vacation detected - travel and regional vibes.', moodTags: ['travel','regional','roadtrip'], bpmRange: [95,120] };
} else if (tod === 'late_night' && (!prep.hasDestination || prep.routeType === 'leisure_undetermined')) {
  if (weather.isRaining) {
    scenario = { id: 'night_drive_rain', label: 'Rainy Night Drive', rationale: 'Rain shifted the late-night mix to melancholic.', moodTags: ['night','melancholic','drive','rain'], bpmRange: [80,105] };
  } else {
    scenario = { id: 'night_drive', label: 'Casual Night Drive', rationale: 'No fixed destination this late - ambient drive mix.', moodTags: ['night','ambient','drive'], bpmRange: [85,105] };
  }
} else if (weather.isRaining && tod === 'evening') {
  scenario = { id: 'rainy_wind_down', label: 'Rainy Wind-Down', rationale: 'Post-work social trip in the rain.', moodTags: ['rain','cozy','wind-down','romantic'], bpmRange: [70,95] };
} else if (tod === 'morning' && prep.hasDestination) {
  scenario = { id: 'morning_rush', label: 'Morning Focus Mix', rationale: 'Commute detected - time-capped focus mix.', moodTags: ['morning','focus','upbeat','motivational'], bpmRange: [110,128] };
} else {
  scenario = { id: 'adaptive_mix', label: 'Adaptive Mix', rationale: 'No strong scenario match - balanced mix.', moodTags: ['morning','night','travel'], bpmRange: [90,120] };
}

const catalog = [
  {id:'m1',title:'Skyline Drive',artist:'Neon Circuit',dur:198,tags:['morning','focus','upbeat']},
  {id:'m2',title:'First Light',artist:'Aurora Kade',dur:210,tags:['morning','focus','motivational']},
  {id:'m3',title:'Green Signal',artist:'Motive',dur:175,tags:['morning','commute','upbeat']},
  {id:'r1',title:'Windowpane',artist:'Soft Static',dur:240,tags:['rain','cozy','wind-down']},
  {id:'r2',title:'Petrichor',artist:'Halide',dur:225,tags:['rain','atmospheric','wind-down']},
  {id:'r3',title:'Slow City Lights',artist:'June Marlowe',dur:250,tags:['rain','romantic','cozy']},
  {id:'g1',title:'Redline',artist:'Voltage District',dur:195,tags:['gym','high-octane','motivational']},
  {id:'g2',title:'Iron Pulse',artist:'Kilowatt',dur:202,tags:['gym','high-octane','aggressive']},
  {id:'g3',title:'Overdrive',artist:'Voltage District',dur:180,tags:['gym','high-octane','motivational']},
  {id:'c1',title:'Cool Down Room',artist:'Delta Fields',dur:220,tags:['gym','cool-down','accomplishment']},
  {id:'c2',title:'Well Earned',artist:'June Marlowe',dur:215,tags:['gym','cool-down','accomplishment']},
  {id:'c3',title:'Steady Now',artist:'Halide',dur:200,tags:['gym','cool-down','accomplishment']},
  {id:'n1',title:'Midnight Loop',artist:'Halide',dur:260,tags:['night','ambient','drive']},
  {id:'n2',title:'Empty Highway',artist:'Aurora Kade',dur:245,tags:['night','lo-fi','drive']},
  {id:'n3',title:'Streetlight Static',artist:'Soft Static',dur:230,tags:['night','melancholic','drive','rain']},
  {id:'t1',title:'Pink City Roads',artist:'Marigold Ensemble',dur:215,tags:['travel','regional','roadtrip']},
  {id:'t2',title:'Bazaar Wind',artist:'Marigold Ensemble',dur:195,tags:['travel','regional','roadtrip']},
  {id:'t3',title:'Fort Road',artist:'Kite & Compass',dur:205,tags:['travel','roadtrip']}
];

const wanted = scenario.moodTags;
const scored = catalog.map(function(t) {
  let overlap = 0;
  for (let i = 0; i < t.tags.length; i++) { if (wanted.indexOf(t.tags[i]) !== -1) overlap++; }
  return { t: t, overlap: overlap };
});
scored.sort(function(a,b){ return b.overlap - a.overlap; });
const candidates = scored.filter(function(s){ return s.overlap > 0; }).map(function(s){ return s.t; });
const pool = candidates.length > 0 ? candidates : catalog.slice(0, 6);

const etaSeconds = route.etaSeconds;
let queue = [];
let elapsed = 0;
let cleanCut = null;

if (!etaSeconds) {
  queue = pool.slice(0, 6);
  elapsed = queue.reduce(function(a,t){ return a + t.dur; }, 0);
} else {
  const budget = Math.max(0, etaSeconds - 20);
  const recent = [];
  for (let i = 0; i < pool.length; i++) {
    const track = pool[i];
    if (elapsed + track.dur > budget) continue;
    if (recent.length > 0 && recent[recent.length - 1] === track.artist) continue;
    queue.push(track);
    recent.push(track.artist);
    elapsed += track.dur;
    if (budget - elapsed < 30) break;
  }
  const remaining = etaSeconds - elapsed;
  const used = {};
  for (let i = 0; i < queue.length; i++) { used[queue[i].id] = true; }
  const leftover = pool.filter(function(t){ return !used[t.id]; });
  if (remaining > 5 && leftover.length > 0) {
    const fit = leftover.filter(function(t){ return t.dur <= remaining; })[0];
    if (fit) {
      queue.push(fit);
      elapsed += fit.dur;
      cleanCut = { trackId: fit.id, fullDurationSec: fit.dur, playSeconds: fit.dur, trimmed: false, boundaryType: 'natural-end' };
    } else {
      const next = leftover[0];
      const playSeconds = Math.max(10, Math.min(next.dur, remaining));
      queue.push(next);
      elapsed += playSeconds;
      cleanCut = { trackId: next.id, fullDurationSec: next.dur, playSeconds: playSeconds, trimmed: true, boundaryType: 'faded-outro' };
    }
  }
}

const formattedQueue = queue.map(function(t) {
  return { id: t.id, title: t.title, artist: t.artist, durationSec: t.dur, source: 'n8n-mock' };
});

return [{
  json: {
    context: { timeOfDay: tod, hour: prep.hour, route: route, weather: weather },
    scenario: scenario,
    queue: {
      queue: formattedQueue,
      totalDurationSec: elapsed,
      capped: Boolean(etaSeconds),
      etaSeconds: etaSeconds,
      cleanCut: cleanCut
    }
  }
}];
